const src = $input.first().json;
const body = src.body && typeof src.body === 'object' ? src.body : src;

if (!body.project_id) throw new Error('payload missing project_id');
if (!body.telegram_chat_id) throw new Error('payload missing telegram_chat_id');
if (!Array.isArray(body.plan) || body.plan.length === 0) throw new Error('payload.plan must be a non-empty array');

for (const step of body.plan) {
  if (typeof step.step_no !== 'number') throw new Error('each plan step needs a numeric step_no');
  if (!step.title) throw new Error(`step ${step.step_no} missing title`);
}

const payload_b64 = Buffer.from(JSON.stringify(body)).toString('base64');

return [{ json: {
  project_id: String(body.project_id),
  telegram_chat_id: String(body.telegram_chat_id),
  plan: body.plan,
  plan_length: body.plan.length,
  brief_summary: (body.brief && body.brief.summary) || '',
  payload_b64
}}];

const prep = $('Prepare').item.json;
return prep.plan.map(step => ({ json: {
  project_id: prep.project_id,
  telegram_chat_id: prep.telegram_chat_id,
  step_no: step.step_no,
  title: step.title,
  description: step.description || '',
  acceptance: step.acceptance || ''
}}));

const stdout = ($json.stdout || '').trim();
const lines  = stdout.split('\n').filter(Boolean);
const last   = lines.length ? lines[lines.length - 1] : '';
let outcome;
try {
  outcome = JSON.parse(last);
} catch (e) {
  throw new Error(`run-step.sh stdout was not JSON: ${last}`);
}
const prep = $('Prepare').item.json;
return [{ json: { ...outcome, telegram_chat_id: prep.telegram_chat_id }}];

// Score 3D is now METRICS-ONLY. The pass/fail decision lives in
// run-step.sh (score >= OA_SCORE_PASS AND critical_issues == 0). This node
// just computes breakdown for Telegram visibility — never blocks.
const prev = $('Parse Outcome').item.json;
let data = { executor: {}, reviewer: {} };
try {
  data = JSON.parse(($json.stdout || '').trim()) || data;
} catch (_) { /* report may be absent on early-block paths — degrade */ }
const executor    = data.executor || {};
const reviewerRaw = data.reviewer || {};
const reviewer    = reviewerRaw.full_review || reviewerRaw;

let obj = 0;
const qg = executor.quality_gates || {};
if (qg.build     && qg.build.passed)     obj += 25;
if (qg.lint      && qg.lint.passed)      obj += 5;
if (qg.typecheck && qg.typecheck.passed) obj += 5;
const tests = qg.tests || {};
const testRatio = (tests.passed_count || 0) / Math.max(tests.total || 1, 1);
obj += Math.round(testRatio * 20);
const acStatus = executor.acceptance_criteria_status || {};
const acMet   = Object.values(acStatus).filter(ac => ac && ac.passed).length;
const acTotal = Object.keys(acStatus).length || 1;
obj += Math.round((acMet / acTotal) * 15);
const issues = reviewer.issues || [];
const critSec = issues.filter(i => i.severity === 'critical' && i.category === 'security').length;
if (critSec === 0) obj += 10;
obj += 10;
obj = Math.min(obj, 100);

const rev = reviewer.review_score || 0;
let pol = 100;
for (const issue of issues) {
  if      (issue.severity === 'critical') pol -= 25;
  else if (issue.severity === 'major')    pol -= 10;
  else if (issue.severity === 'minor')    pol -= 3;
}
pol = Math.max(pol, 0);
const finalScore    = (obj * 0.5) + (rev * 0.35) + (pol * 0.15);
const criticalCount = issues.filter(i => i.severity === 'critical').length;

return [{ json: {
  ...prev,
  objective_score: obj,
  review_score: rev,
  policy_score: pol,
  final_score: Math.round(finalScore * 100) / 100,
  critical_issues: criticalCount,
  verdict: reviewer.review_verdict || null,
  retry_instructions: reviewer.retry_instructions || ''
}}];
